import{_ as o,C as n,o as l,c as s,E as i,w as r,a as t,a0 as d}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Moving to Ireland","description":"Immigration pathways and relocation guide for Ireland","frontmatter":{"layout":"doc","title":"Moving to Ireland","description":"Immigration pathways and relocation guide for Ireland"},"headers":[],"relativePath":"europe/ireland/moving-there.md","filePath":"europe/ireland/moving-there.md","lastUpdated":null}'),h={name:"europe/ireland/moving-there.md"};function c(m,e,u,g,f,p){const a=n("Badge");return l(),s("div",null,[i(a,{variant:"green"},{default:r(()=>[...e[0]||(e[0]=[t("EU/EEA: Free Movement",-1)])]),_:1}),i(a,{variant:"yellow"},{default:r(()=>[...e[1]||(e[1]=[t("Non-EU: Critical Skills Visa",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="moving-to-ireland" tabindex="-1">Moving to Ireland <a class="header-anchor" href="#moving-to-ireland" aria-label="Permalink to &quot;Moving to Ireland&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><p>Free movement applies. No registration requirement for EU citizens, but you need a valid passport or national ID card. After 5 years of residence, you can apply for permanent residence.</p><h3 id="uk-citizens" tabindex="-1">UK Citizens <a class="header-anchor" href="#uk-citizens" aria-label="Permalink to &quot;UK Citizens&quot;">​</a></h3><p>Under the Common Travel Area (CTA), UK citizens have the right to live, work, and access services in Ireland without a visa. No registration required, but you should bring proof of residence and access healthcare through the HSE.</p><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><ul><li><strong>Critical Skills Employment Permit</strong>: For occupations on the Critical Skills List (ICT, engineering, healthcare). Fast-track processing, path to long-term residence after 2 years.</li><li><strong>General Employment Permit</strong>: For other job offers. Labour market test required. Valid for 2 years.</li><li><strong>Stamp 4 (Long Stay)</strong>: For researchers, academics, and family members.</li><li><strong>Student Visa</strong>: For study at recognised institutions. Part-time work permitted (20 hours/week term, 40 hours/week holidays).</li><li><strong>Family Reunification</strong>: For spouses, civil partners, and de facto partners (2+ years cohabitation).</li></ul><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Ireland does not have a specific digital nomad visa. Remote workers typically enter on a <strong>Stamp 3 (Visitor)</strong> for short stays (up to 90 days, no work allowed for non-EEA), or use the <strong>Critical Skills</strong> or <strong>General Employment Permit</strong> routes if employed by an Irish company. A new digital nomad scheme is being discussed but not yet legislated.</p><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] Obtain necessary visa/work permit (non-EU)</li><li>[ ] Arrange health insurance (required for non-EU visa holders)</li><li>[ ] Research housing (Dublin is very expensive; Cork, Galway, Limerick more affordable)</li><li>[ ] Gather medical records and HRT documentation (English is fine)</li><li>[ ] Notify your bank and redirect mail</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register with immigration (GNIB/IRP card) — within 90 days for non-EU</li><li>[ ] Apply for PPS (Personal Public Service) number — essential for work, healthcare, taxes</li><li>[ ] Register with a GP (find trans-friendly GPs through TENI directory)</li><li>[ ] Open an Irish bank account (AIB, Bank of Ireland, Revolut)</li><li>[ ] Apply for a Public Services Card</li><li>[ ] Get an Irish SIM card (Vodafie, Three, Eir)</li><li>[ ] Register with the National Gender Service or find a private endocrinologist</li><li>[ ] Connect with TENI for local trans community resources</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li>Monthly rent (1-bed): €1,500-2,200 (Dublin), €900-1,400 (Cork, Galway)</li><li>Monthly budget (single person): €1,000-1,500 excluding rent</li><li>Public transport: €80-120/month (Dublin Leap Card), limited in rural areas</li></ul><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><p>Temperate maritime — mild winters (4-8°C), cool summers (15-20°C). Frequent rain year-round. Rarely snows.</p><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><p>English and Irish (Gaeilge) are official languages. English is the primary language of daily life. Irish is spoken in Gaeltacht regions but is not needed for living in Ireland.</p>',22))])}const v=o(h,[["render",c]]);export{b as __pageData,v as default};
